#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    int min_val = INT_MAX;
    for (int i = 0; i < n; ++i) {
        int x;
        cin >> x;
        if (x < min_val) {
            min_val = x;
        }
    }

    cout << min_val << '\n';

    return 0;
}
